html = "<!DOCTYPE html>\n<html>\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n<style>\n:root{\n  --bg:#070910; --cell:#151c29; --cell2:#192233; --line:#303847;\n  --gold:#d8b05c; --text:#edf1f7; --muted:#8e98aa;\n  --green:#12683f; --green2:#20a96b; --purple:#3a2c5c;\n  --pink:#d95772; --blue:#61c8e8; --mint:#47e6a0;\n}\n*{box-sizing:border-box}\nhtml,body{\n  margin:0; min-height:100%;\n  background:\n    radial-gradient(circle at 50% -8%, rgba(216,176,92,.13), transparent 24%),\n    radial-gradient(circle at 10% 38%, rgba(97,200,232,.055), transparent 20%),\n    radial-gradient(circle at 92% 35%, rgba(217,87,114,.045), transparent 20%),\n    linear-gradient(180deg,#090b12 0%,#05060a 100%);\n  color:var(--text); font-family:Inter,ui-sans-serif,system-ui,\"Segoe UI\",Arial,sans-serif;\n  overflow-x:hidden;\n}\n.app{position:relative;width:min(94vw,640px);margin:0 auto;padding:10px 8px 24px;z-index:2}\n.bg-bit{position:fixed;pointer-events:none;opacity:.22;z-index:0;filter:drop-shadow(0 0 8px rgba(216,176,92,.2))}\n.bg-bit.die{width:26px;height:26px;border:2px solid rgba(216,176,92,.35);background:rgba(16,23,37,.7);animation:drift 8s ease-in-out infinite alternate}\n.bg-bit.die:before{content:\"\";position:absolute;inset:6px;background:radial-gradient(circle at 20% 20%,var(--gold) 0 2px,transparent 3px),radial-gradient(circle at 80% 20%,var(--gold) 0 2px,transparent 3px),radial-gradient(circle at 50% 50%,var(--gold) 0 2px,transparent 3px),radial-gradient(circle at 20% 80%,var(--gold) 0 2px,transparent 3px),radial-gradient(circle at 80% 80%,var(--gold) 0 2px,transparent 3px)}\n.bg-bit.board{width:32px;height:32px;border:1px solid rgba(97,200,232,.28);background:linear-gradient(90deg,transparent 31%,rgba(97,200,232,.25) 32% 35%,transparent 36% 64%,rgba(97,200,232,.25) 65% 68%,transparent 69%),linear-gradient(0deg,transparent 31%,rgba(97,200,232,.25) 32% 35%,transparent 36% 64%,rgba(97,200,232,.25) 65% 68%,transparent 69%),rgba(16,23,37,.55);animation:drift2 9s ease-in-out infinite alternate}\n.bg-bit.chip{width:20px;height:20px;border-radius:50%;border:3px dashed rgba(217,87,114,.35);animation:spinDrift 7s linear infinite}\n.b1{left:8vw;top:17vh}.b2{right:12vw;top:23vh;animation-delay:1.3s}.b3{left:13vw;bottom:20vh;animation-delay:.7s}.b4{right:9vw;bottom:18vh;animation-delay:2.1s}.b5{left:4vw;top:58vh;animation-delay:2.8s}.b6{right:5vw;top:62vh;animation-delay:1.7s}\n@keyframes drift{from{transform:translateY(0) rotate(-8deg);opacity:.16}to{transform:translateY(-26px) rotate(12deg);opacity:.48}}\n@keyframes drift2{from{transform:translate(0,0) rotate(4deg);opacity:.14}to{transform:translate(12px,-24px) rotate(-8deg);opacity:.42}}\n@keyframes spinDrift{0%{transform:translateY(0) rotate(0);opacity:.15}50%{transform:translateY(-18px) rotate(180deg);opacity:.42}100%{transform:translateY(0) rotate(360deg);opacity:.15}}\n.header{text-align:center;margin:4px auto 8px}\n.logo-card{display:inline-block;padding:10px 18px 12px;border:1px solid rgba(216,176,92,.16);background:rgba(11,15,23,.58);box-shadow:0 12px 40px rgba(0,0,0,.28),inset 0 0 24px rgba(255,255,255,.025)}\n.kicker{color:var(--muted);font-size:11px;font-weight:850;letter-spacing:.22em;text-transform:uppercase}\n.title{margin-top:2px;color:var(--gold);font-size:clamp(28px,5.2vw,46px);font-weight:950;letter-spacing:-.055em;line-height:.96;text-shadow:0 0 14px rgba(216,176,92,.22);animation:softTitle 4s ease-in-out infinite}\n@keyframes softTitle{0%,100%{filter:brightness(.95)}50%{filter:brightness(1.14)}}\n.toolbar{width:max-content;max-width:100%;margin:0 auto 10px;padding:5px;display:flex;gap:5px;align-items:center;background:rgba(13,17,26,.92);border:1px solid rgba(255,255,255,.08);box-shadow:0 10px 24px rgba(0,0,0,.28)}\n.icon-btn{width:34px;height:34px;border:1px solid rgba(216,176,92,.35);background:#111722;color:var(--gold);cursor:pointer;display:grid;place-items:center;transition:transform .14s ease,box-shadow .14s ease,filter .14s ease,border-color .14s ease}\n.icon-btn svg{width:18px;height:18px;stroke:currentColor;fill:none;stroke-width:2.4;stroke-linecap:round;stroke-linejoin:round}\n.icon-btn:hover{transform:translateY(-1px);filter:brightness(1.15);border-color:var(--gold);box-shadow:0 0 14px rgba(216,176,92,.18)}\n.icon-btn:active{transform:scale(.96)}\n.board-select{height:34px;border:1px solid rgba(216,176,92,.35);background:#111722;color:var(--gold);font-weight:850;outline:none;padding:0 7px;cursor:pointer}\n.boards{display:grid;gap:12px;justify-content:center}\n.boards.one{grid-template-columns:minmax(300px,min(76vmin,490px))}\n.boards.two,.boards.three,.boards.four{grid-template-columns:repeat(2,minmax(260px,1fr));width:min(94vw,820px);margin-left:50%;transform:translateX(-50%)}\n.boards.five,.boards.six{grid-template-columns:repeat(3,minmax(220px,1fr));width:min(96vw,940px);margin-left:50%;transform:translateX(-50%)}\n.board-shell{padding:3px;background:#1a202a;border:2px solid #4b5363;box-shadow:0 0 22px rgba(0,0,0,.34),0 0 18px rgba(216,176,92,.05)}\n.board{display:grid;grid-template-columns:repeat(5,1fr);gap:2px;background:#303847;padding:2px;aspect-ratio:1/1}\n.cell{position:relative;overflow:hidden;border:1px solid #2d3543;background:var(--cell);color:var(--text);font-size:clamp(9px,1.48vw,13px);line-height:1.08;font-weight:830;text-align:center;padding:5px;cursor:pointer;display:flex;align-items:center;justify-content:center;user-select:none;transition:transform .12s ease,filter .12s ease,border-color .12s ease,box-shadow .12s ease,background .12s ease}\n.cell:nth-child(even){background:var(--cell2)}\n.boards.two .cell,.boards.three .cell,.boards.four .cell{font-size:clamp(8px,1vw,11px)}\n.boards.five .cell,.boards.six .cell{font-size:clamp(7px,.75vw,9px)}\n.cell:hover{transform:translateY(-1px);filter:brightness(1.08);border-color:rgba(216,176,92,.65);box-shadow:0 0 10px rgba(216,176,92,.12)}\n.cell.free{background:var(--purple)!important;color:var(--gold);border-color:rgba(216,176,92,.62);font-style:italic;cursor:default;transform:none!important}\n.cell.free:hover{filter:none;box-shadow:none}\n.cell.marked{background:linear-gradient(180deg,var(--green2),var(--green))!important;color:#edfff5;border-color:rgba(71,230,160,.8);box-shadow:inset 0 0 14px rgba(255,255,255,.08),0 0 12px rgba(71,230,160,.16);animation:markPop .22s ease}\n.cell.marked:after{content:\"\u2713\";position:absolute;right:5px;bottom:0;font-size:16px;opacity:.34}\n@keyframes markPop{0%{transform:scale(.97)}70%{transform:scale(1.035)}100%{transform:scale(1)}}\n.cell.rolling:not(.free){animation:cellFlip .28s ease}\n@keyframes cellFlip{0%{filter:brightness(.65);transform:translateY(3px)}60%{filter:brightness(1.25);transform:translateY(-2px)}100%{filter:brightness(1);transform:translateY(0)}}\n.modal-backdrop{position:fixed;inset:0;background:rgba(0,0,0,.68);display:none;align-items:center;justify-content:center;z-index:50;padding:20px}\n.modal-backdrop.show{display:flex;animation:fadeIn .16s ease}\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n.modal{width:min(92vw,390px);background:#101722;border:1px solid rgba(216,176,92,.25);padding:18px;box-shadow:0 0 36px rgba(0,0,0,.55);animation:modalIn .2s ease}\n@keyframes modalIn{from{transform:translateY(8px) scale(.98);opacity:0}to{transform:translateY(0) scale(1);opacity:1}}\n.modal h2{margin:0 0 10px;color:var(--gold);font-size:30px;line-height:1}.modal p{color:var(--text);margin:8px 0;font-weight:720}\n.close{margin-top:14px;width:100%;height:36px;border:1px solid rgba(216,176,92,.35);background:#14100a;color:var(--gold);font-weight:900;cursor:pointer}\n.bingo-modal .modal{text-align:center}.bingo-modal h2{font-size:clamp(52px,10vw,86px);animation:jackpot .72s ease-in-out infinite alternate;text-shadow:0 0 16px var(--gold),0 0 32px var(--pink)}\n@keyframes jackpot{from{transform:scale(1);filter:brightness(1)}to{transform:scale(1.055);filter:brightness(1.28)}}\n.confetti{position:fixed;top:-20px;font-size:18px;z-index:60;animation:fall 1.25s linear forwards}\n@keyframes fall{to{transform:translateY(110vh) rotate(380deg);opacity:.2}}\n@media(max-width:760px){.boards.two,.boards.three,.boards.four,.boards.five,.boards.six{grid-template-columns:1fr;width:min(94vw,500px)}.cell,.boards.two .cell,.boards.three .cell,.boards.four .cell,.boards.five .cell,.boards.six .cell{font-size:clamp(9px,2.35vw,12px)}}\n</style>\n</head>\n<body>\n  <div class=\"bg-bit die b1\"></div><div class=\"bg-bit board b2\"></div><div class=\"bg-bit chip b3\"></div>\n  <div class=\"bg-bit die b4\"></div><div class=\"bg-bit board b5\"></div><div class=\"bg-bit chip b6\"></div>\n  <div class=\"app\">\n    <div class=\"header\"><div class=\"logo-card\"><div class=\"kicker\">WOG community card</div><div class=\"title\">Low Rank Bingo</div></div></div>\n    <div class=\"toolbar\">\n      <button class=\"icon-btn\" title=\"Roll\" onclick=\"rollBoards()\"><svg viewBox=\"0 0 24 24\"><rect x=\"4\" y=\"4\" width=\"16\" height=\"16\"></rect><circle cx=\"8\" cy=\"8\" r=\"1\"></circle><circle cx=\"16\" cy=\"8\" r=\"1\"></circle><circle cx=\"12\" cy=\"12\" r=\"1\"></circle><circle cx=\"8\" cy=\"16\" r=\"1\"></circle><circle cx=\"16\" cy=\"16\" r=\"1\"></circle></svg></button>\n      <button class=\"icon-btn\" title=\"Reset\" onclick=\"resetMarks()\"><svg viewBox=\"0 0 24 24\"><path d=\"M4 12a8 8 0 1 0 3-6\"></path><path d=\"M4 4v6h6\"></path></svg></button>\n      <button class=\"icon-btn\" title=\"Rules\" onclick=\"openRules()\"><svg viewBox=\"0 0 24 24\"><path d=\"M9.5 9a2.5 2.5 0 1 1 4.3 1.7c-1.2 1-1.8 1.5-1.8 3.1\"></path><path d=\"M12 18h.01\"></path><circle cx=\"12\" cy=\"12\" r=\"9\"></circle></svg></button>\n      <select class=\"board-select\" id=\"boardCount\" title=\"Boards\" onchange=\"setBoardCount(this.value)\">\n        <option value=\"1\">1 board</option><option value=\"2\">2 boards</option><option value=\"3\">3 boards</option><option value=\"4\">4 boards</option><option value=\"5\">5 boards</option><option value=\"6\">6 boards</option>\n      </select>\n    </div>\n    <div id=\"boards\" class=\"boards one\"></div>\n  </div>\n  <div id=\"rulesModal\" class=\"modal-backdrop\" onclick=\"closeRules(event)\"><div class=\"modal\"><h2>Rules</h2><p>\u2022 Click a square when it happens.</p><p>\u2022 Free space starts marked.</p><p>\u2022 5 in a row wins.</p><p>\u2022 Rows, columns, diagonals count.</p><button class=\"close\" onclick=\"hideRules()\">Close</button></div></div>\n  <div id=\"bingoModal\" class=\"modal-backdrop bingo-modal\" onclick=\"hideBingo()\"><div class=\"modal\"><h2>BINGO!</h2><p>jackpot hit</p><button class=\"close\" onclick=\"hideBingo()\">Close</button></div></div>\n<script>\nconst ITEMS = [\"\\\"add 5th gen aircrafts!\\\"\", \"DOGSHIT opinion or suggestion\", \"corny ass profile/pfp\", \"\\\"errrmm is all bvr so it's LAME\\\"\", \"chaff = flare\", \"thinks they're good\", \"nerf f14a or phoenix missiles\", \"compares wog to wt\", \"doesn't know any bfm/acm\", \"\\\"codes?\\\"\", \"add their favorite niche aircraft\", \"\\\"i have a life/whats wrong with low rank\\\"\", \"realized they have no image perms\", \"\\\"My rank ingame is higher\\\"\", \"extremely biased\", \"intentional rule breaking\", \"\\\"when update?\\\" bro the update is soon chilllll\", \"bitching about killstealing\", \"\\\"(decent plane) is so bad\\\"\", \"\\\"(premium plane) is p2w...\\\"\", \"\\\"add (insert nation) tree!\\\"\", \"can't lose their argument\", \"rants about russian aircrafts\", \"huge fuckass ego\"];\nlet boards=[]; let marked=[]; let boardCount=1; let rolling=false;\nfunction shuffle(arr){const a=[...arr];for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}\nfunction makeBoard(){const items=shuffle(ITEMS);const board=[];let idx=0;for(let i=0;i<25;i++){if(i===12)board.push(\"FREE SPACE\");else board.push(items[idx++]);}return board;}\nfunction classForCount(){if(boardCount===1)return\"one\";if(boardCount===2)return\"two\";if(boardCount===3)return\"three\";if(boardCount===4)return\"four\";if(boardCount===5)return\"five\";return\"six\";}\nfunction setBoardCount(n){boardCount=Math.max(1,Math.min(6,Number(n)));while(boards.length<boardCount){boards.push(makeBoard());marked.push(new Set([12]));}while(boards.length>boardCount){boards.pop();marked.pop();}render();}\nfunction render(){const root=document.getElementById(\"boards\");root.className=\"boards \"+classForCount();root.innerHTML=\"\";for(let b=0;b<boardCount;b++){const shell=document.createElement(\"div\");shell.className=\"board-shell\";const board=document.createElement(\"div\");board.className=\"board\";for(let i=0;i<25;i++){const cell=document.createElement(\"div\");cell.className=\"cell\";if(i===12)cell.classList.add(\"free\");if(marked[b].has(i))cell.classList.add(\"marked\");cell.textContent=boards[b][i];cell.onclick=()=>toggleCell(b,i);board.appendChild(cell);}shell.appendChild(board);root.appendChild(shell);}}\nfunction toggleCell(b,i){if(i===12||rolling)return;const root=document.getElementById(\"boards\");const boardEl=root.children[b].querySelector(\".board\");const cell=boardEl.children[i];if(marked[b].has(i)){marked[b].delete(i);cell.classList.remove(\"marked\");}else{marked[b].add(i);cell.classList.add(\"marked\");}if(hasBingo(marked[b]))showBingo();}\nfunction winLines(){const lines=[];for(let r=0;r<5;r++)lines.push([0,1,2,3,4].map(c=>r*5+c));for(let c=0;c<5;c++)lines.push([0,1,2,3,4].map(r=>r*5+c));lines.push([0,6,12,18,24]);lines.push([4,8,12,16,20]);return lines;}\nfunction hasBingo(set){return winLines().some(line=>line.every(i=>set.has(i)));}\nfunction rollBoards(){if(rolling)return;rolling=true;const allCells=()=>Array.from(document.querySelectorAll(\".cell:not(.free)\"));let steps=10;function spin(step){const tempBoards=Array.from({length:boardCount},()=>makeBoard());allCells().forEach((cell,idx)=>{const boardIndex=Math.floor(idx/24);const innerIndex=idx%24;const pool=tempBoards[boardIndex].filter((_,i)=>i!==12);cell.textContent=pool[innerIndex]||ITEMS[Math.floor(Math.random()*ITEMS.length)];cell.classList.remove(\"marked\");cell.classList.remove(\"rolling\");void cell.offsetWidth;cell.classList.add(\"rolling\");});if(step<steps){setTimeout(()=>spin(step+1),55+step*10);}else{boards=Array.from({length:boardCount},()=>makeBoard());marked=Array.from({length:boardCount},()=>new Set([12]));rolling=false;render();}}spin(0);}\nfunction resetMarks(){marked=Array.from({length:boardCount},()=>new Set([12]));render();}\nfunction openRules(){document.getElementById(\"rulesModal\").classList.add(\"show\")}function hideRules(){document.getElementById(\"rulesModal\").classList.remove(\"show\")}function closeRules(e){if(e.target.id===\"rulesModal\")hideRules()}function showBingo(){document.getElementById(\"bingoModal\").classList.add(\"show\");confettiBurst()}function hideBingo(){document.getElementById(\"bingoModal\").classList.remove(\"show\")}\nfunction confettiBurst(){const shapes=[\"\u2726\",\"\u2605\",\"\u2666\",\"\u25cf\",\"\u2660\",\"\u2665\"];const colors=[\"#d8b05c\",\"#d95772\",\"#47e6a0\",\"#61c8e8\",\"#b517ff\",\"#ffffff\"];for(let i=0;i<32;i++){const s=document.createElement(\"div\");s.className=\"confetti\";s.textContent=shapes[Math.floor(Math.random()*shapes.length)];s.style.left=Math.random()*100+\"vw\";s.style.color=colors[Math.floor(Math.random()*colors.length)];s.style.animationDelay=Math.random()*.15+\"s\";document.body.appendChild(s);setTimeout(()=>s.remove(),1500);}}\ndocument.addEventListener(\"keydown\",e=>{if(e.key===\"Escape\"){hideRules();hideBingo();}});\nboards=[makeBoard()];marked=[new Set([12])];render();\n</script>\n</body>\n</html>\n"

components.html(html, height=900, scrolling=True)
